function wtf() {
    jsmediatags.read(event.target.files[0], {
        onSuccess: function(tag) {
            if (tag.tags.picture) {
                var base64String = "";
                for (var i =  0; i < tag.tags.picture.data.length; i++) {
                base64String += String.fromCharCode(tag.tags.picture.data[i]);
                }
                var base64Image = "data:image/jpeg;base64," + window.btoa(base64String);
                console.log(base64Image);
                getMostCommonColor(base64Image).then((color) => {
                    console.log(color);
                    document.body.style.backgroundColor = color;
                })
                document.getElementById("cover").src = base64Image;
            }
        }
    });
    // document.getElementById("cover").src = dbgImage;
    // getMostCommonColor(dbgImage).then((color) => {
    //     console.log(color);
    //     document.body.style.backgroundColor = color;
    // })
}

function getMostCommonColor(base64Image) {
    return new Promise((resolve, reject) => {
        let img = new Image();
        img.onload = function() {
            let canvas = document.createElement("canvas");
            canvas.width = this.width;
            canvas.height = this.height;
            let ctx = canvas.getContext("2d");
            ctx.drawImage(this, 0, 0);
            let imageData = ctx.getImageData(0, 0, this.width, this.height);
            let pixels = imageData.data;
            let colorMap = {};

            for (let i = 0; i < pixels.length; i += 4) {
                let r = pixels[i];
                let g = pixels[i + 1];
                let b = pixels[i + 2];
                let a = pixels[i + 3];
                // skip transparent pixels
                if (a === 0) continue;
                let color = `rgba(${r},${g},${b},${a})`;
                colorMap[color] = (colorMap[color] || 0) + 1;
            }

            let maxCount = 0;
            let mostCommonColor;
            for (let color in colorMap) {
                if (colorMap[color] > maxCount) {
                    maxCount = colorMap[color];
                    mostCommonColor = color;
                }
            }

            resolve(mostCommonColor);
        };
        img.onerror = function() {
            reject(new Error("Failed to load image!"));
        };
        img.src = base64Image;
    });
}
